83: func (obj *Unstructured) EachListItem(fn func(runtime.Object) error) error {
84: 	field, ok := obj.Object["items"]
85: 	if !ok {
86: 		return errors.New("content is not a list")
87: 	}
88: 	items, ok := field.([]interface{})
